SELECT sg.name, ct.semester, ct.code, ct.subject_name, ct.hours_per_week, ct.teacher_name, ct.room_type
FROM study_groups sg
JOIN majors m ON m.id = sg.major_id
JOIN curriculum_templates ct ON ct.major_short = m.short_name AND ct.course = sg.course
WHERE sg.name <> 'COM-22';

SELECT
    MIN(cr.subject_name),
    cr.code,
    MAX(cr.hours_per_week) * 15,
    MAX(cr.hours_per_week),
    CASE
        WHEN COUNT(DISTINCT m.id) = 1 THEN MIN(m.id)
        ELSE NULL
    END
FROM curriculum_rows cr
JOIN study_groups sg ON sg.name = cr.group_name
JOIN majors m ON m.id = sg.major_id
GROUP BY cr.code;

SELECT DISTINCT s.id, sg.id
FROM curriculum_rows cr
JOIN subjects s ON s.code = cr.code
JOIN study_groups sg ON sg.name = cr.group_name;

SELECT DISTINCT s.id, t.id
FROM curriculum_rows cr
JOIN subjects s ON s.code = cr.code
JOIN teachers t ON t.full_name = cr.teacher_name
WHERE cr.teacher_name IS NOT NULL;

    timetable_id,
    subject_id,
    teacher_id,
    hours_per_week,
    shift,
    room_type_required,
    hours_splitting,
    generated_lessons_count,
    specific_room_id,
    placement_status,
    requires_manual_input,
    failure_reason
)
SELECT
    tt.id,
    s.id,
    t.id,
    cr.hours_per_week,
    CASE WHEN cr.hours_per_week >= 6 THEN 'ANY' ELSE 'MORNING' END,
    cr.room_type,
    CASE cr.hours_per_week
        WHEN 12 THEN '4+4+4'
        WHEN 8 THEN '4+4'
        WHEN 6 THEN '3+3'
        WHEN 4 THEN '2+2'
        WHEN 3 THEN '3'
        WHEN 2 THEN '2'
        WHEN 1 THEN '1'
        ELSE 'manual'
    END,
    0,
    NULL,
    'PENDING',
    FALSE,
    'seed:' || cr.group_name || ':' || cr.semester || ':' || cr.code
FROM curriculum_rows cr
JOIN subjects s ON s.code = cr.code
LEFT JOIN teachers t ON t.full_name = cr.teacher_name
JOIN timetables tt ON tt.semester = cr.semester;

SELECT a.id, sg.id
FROM curriculum_rows cr
JOIN subjects s ON s.code = cr.code
JOIN study_groups sg ON sg.name = cr.group_name
JOIN timetables tt ON tt.semester = cr.semester
JOIN assignments a ON a.failure_reason = 'seed:' || cr.group_name || ':' || cr.semester || ':' || cr.code;

UPDATE assignments
SET failure_reason = NULL
WHERE failure_reason LIKE 'seed:%';

DO $$
DECLARE
    missing_count integer;
BEGIN
    SELECT COUNT(*)
    INTO missing_count
    FROM study_groups sg
    WHERE NOT EXISTS (
        SELECT 1
        FROM assignment_groups ag
        WHERE ag.group_id = sg.id
    );

    IF missing_count > 0 THEN
        RAISE EXCEPTION 'Seed validation failed: % study groups have no assignments', missing_count;
    END IF;
END $$;
